// Prepare data for graph ingestion with batching support
const input = $input.first().json.body;

const requestId = input.requestId || 'unknown';
const companyName = input.companyName || 'Unknown Company';
const extractedData = input.extractedData || [];
const categories = input.categories || {};
const source = input.source || 'manual';

// Flatten all data into individual items for processing
const dataItems = [];

// Add category-based data points
for (const [category, data] of Object.entries(categories)) {
  if (data.examples && Array.isArray(data.examples)) {
    for (const example of data.examples) {
      dataItems.push({
        type: 'datapoint',
        category: category,
        value: example,
        riskLevel: data.riskLevel || 'MEDIUM'
      });
    }
  }
}

// Add extracted entities
for (const entity of extractedData) {
  dataItems.push({
    type: entity.type || 'entity',
    category: entity.category || 'UNKNOWN',
    value: entity.value,
    riskLevel: entity.riskLevel || 'MEDIUM'
  });
}

return {
  json: {
    requestId,
    companyName,
    dataItems,
    totalItems: dataItems.length,
    batchSize: 50,
    currentBatch: 0,
    processedCount: 0,
    source,
    ingestStarted: new Date().toISOString()
  }
};

// Get current batch of items
const inputData = $('2. Prepare Input & Batch Queue').first().json;
const allItems = inputData.dataItems;
const batchSize = inputData.batchSize;
const batchIndex = $('5. Process in Batches of 50').first().json.$batchIndex || 0;

const startIdx = batchIndex * batchSize;
const endIdx = Math.min(startIdx + batchSize, allItems.length);
const currentBatch = allItems.slice(startIdx, endIdx);

return {
  json: {
    ...inputData,
    currentBatch: currentBatch,
    currentBatchIndex: batchIndex,
    batchStartIdx: startIdx,
    batchEndIdx: endIdx,
    itemsInBatch: currentBatch.length,
    progressPercent: Math.round((endIdx / allItems.length) * 100)
  }
};

// Parse AI output and validate Cypher statements
const aiOutput = $input.first().json.output || $input.first().json.text || '';
const inputData = $('6. Get Current Batch').first().json;

let statements = [];
let parseError = null;

try {
  // Find JSON array in response
  const jsonMatch = aiOutput.match(/\[\s*\{[\s\S]*\}\s*\]/); 
  if (jsonMatch) {
    statements = JSON.parse(jsonMatch[0]);
  } else {
    // Try parsing entire output as JSON
    statements = JSON.parse(aiOutput);
  }
} catch (e) {
  parseError = e.message;
  // Create fallback statement for company
  statements = [{
    description: 'Fallback: Create company node',
    cypher: `MERGE (c:Company {name: '${inputData.companyName.replace(/'/g, "''")}'})
             SET c.updated_at = datetime()`,
    isValid: true,
    matchesSource: true
  }];
}

// Filter to only valid, verified statements
const validStatements = statements.filter(s => 
  s.cypher && 
  s.isValid !== false && 
  s.matchesSource !== false &&
  (s.cypher.toUpperCase().includes('MERGE') || s.cypher.toUpperCase().includes('CREATE'))
);

return {
  json: {
    ...inputData,
    statements: validStatements,
    statementCount: validStatements.length,
    parseError: parseError,
    validationComplete: true
  }
};

// Prepare Cypher for Neo4j HTTP API execution
const inputData = $input.first().json;
const statements = inputData.statements || [];

// Format statements for Neo4j HTTP transaction API
const neo4jStatements = statements.map(s => ({
  statement: s.cypher
}));

return {
  json: {
    ...inputData,
    neo4jPayload: {
      statements: neo4jStatements
    }
  }
};

// Process Neo4j response and track results
const neo4jResponse = $input.first().json;
const inputData = $('10. Prepare Neo4j Request').first().json;

let successCount = 0;
let errorCount = 0;
let errors = [];

// Check if response contains results or errors
if (neo4jResponse.body) {
  const body = typeof neo4jResponse.body === 'string' ? JSON.parse(neo4jResponse.body) : neo4jResponse.body;

  if (body.results) {
    successCount = body.results.length;
  }

  if (body.errors && body.errors.length > 0) {
    errorCount = body.errors.length;
    errors = body.errors.map(e => e.message || e.code);
  }
} else if (neo4jResponse.statusCode >= 400) {
  errorCount = inputData.statementCount;
  errors.push(`HTTP ${neo4jResponse.statusCode}: ${neo4jResponse.statusMessage}`);
} else {
  successCount = inputData.statementCount;
}

return {
  json: {
    requestId: inputData.requestId,
    companyName: inputData.companyName,
    batchIndex: inputData.currentBatchIndex,
    progressPercent: inputData.progressPercent,
    statementsExecuted: successCount,
    statementsErrored: errorCount,
    errors: errors,
    totalItems: inputData.totalItems,
    batchComplete: true
  }
};

// Log skipped batch due to no valid statements
const inputData = $input.first().json;

return {
  json: {
    requestId: inputData.requestId,
    companyName: inputData.companyName,
    batchIndex: inputData.currentBatchIndex,
    progressPercent: inputData.progressPercent,
    statementsExecuted: 0,
    statementsErrored: 0,
    errors: ['No valid statements generated for this batch'],
    totalItems: inputData.totalItems,
    batchComplete: true,
    skipped: true
  }
};

// Aggregate all batch results
const allBatches = $input.all();
const inputData = $('2. Prepare Input & Batch Queue').first().json;

let totalExecuted = 0;
let totalErrored = 0;
const allErrors = [];

for (const batch of allBatches) {
  totalExecuted += batch.json.statementsExecuted || 0;
  totalErrored += batch.json.statementsErrored || 0;
  if (batch.json.errors) {
    allErrors.push(...batch.json.errors);
  }
}

return {
  json: {
    success: totalErrored === 0,
    requestId: inputData.requestId,
    companyName: inputData.companyName,
    totalItemsProcessed: inputData.totalItems,
    statementsExecuted: totalExecuted,
    statementsErrored: totalErrored,
    errors: allErrors.slice(0, 10),
    ingestCompleted: new Date().toISOString()
  }
};

// No items to process response
const inputData = $('2. Prepare Input & Batch Queue').first().json;

return {
  json: {
    success: false,
    requestId: inputData.requestId,
    companyName: inputData.companyName,
    error: 'No data items to ingest',
    statementsExecuted: 0,
    ingestCompleted: new Date().toISOString()
  }
};
